import React, { useEffect } from 'react';
import { useSelector, useDispatch } from 'react-redux';
import { motion } from 'framer-motion';
import { Link } from 'react-router-dom';
import { fetchLessons } from '../store/slices/lessonSlice';
import Navbar from '../components/Common/Navbar';
import StreakCalendar from '../components/Dashboard/StreakCalendar';
import LessonCard from '../components/Dashboard/LessonCard';
import XPProgress from '../components/Dashboard/XPProgress';
import AchievementBadge from '../components/Dashboard/AchievementBadge';
import DailyGoal from '../components/Dashboard/DailyGoal';

const Dashboard = () => {
  const dispatch = useDispatch();
  const { user } = useSelector(state => state.auth);
  const { lessons, loading } = useSelector(state => state.lesson);

  useEffect(() => {
    dispatch(fetchLessons());
  }, [dispatch]);

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: { staggerChildren: 0.1 }
    }
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: { opacity: 1, y: 0 }
  };

  return (
    <div className="min-h-screen bg-gray-950 text-white">
      <Navbar />
      
      <div className="max-w-7xl mx-auto px-4 py-8">
        
        {/* Welcome Section */}
        <motion.div
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
          className="mb-8"
        >
          <h1 className="text-3xl font-bold">
            Namaste, {user?.full_name?.split(' ')[0]}! 🙏
          </h1>
          <p className="text-gray-400 mt-1">
            {user?.streak_days > 0 
              ? `🔥 ${user.streak_days} day streak! Keep it up!`
              : 'Start learning ISL today!'}
          </p>
        </motion.div>

        {/* Stats Grid */}
        <motion.div
          variants={containerVariants}
          initial="hidden"
          animate="visible"
          className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8"
        >
          {[
            { label: 'XP Points', value: user?.xp_points || 0, icon: '⚡', color: 'from-yellow-600 to-orange-600' },
            { label: 'Level', value: user?.level || 1, icon: '🏆', color: 'from-purple-600 to-pink-600' },
            { label: 'Day Streak', value: user?.streak_days || 0, icon: '🔥', color: 'from-red-600 to-orange-500' },
            { label: 'Signs Learned', value: user?.total_signs_learned || 0, icon: '👋', color: 'from-green-600 to-teal-600' },
          ].map((stat, i) => (
            <motion.div
              key={i}
              variants={itemVariants}
              className={`bg-gradient-to-br ${stat.color} rounded-2xl p-5`}
            >
              <div className="text-3xl mb-2">{stat.icon}</div>
              <div className="text-3xl font-bold">{stat.value.toLocaleString()}</div>
              <div className="text-sm opacity-80">{stat.label}</div>
            </motion.div>
          ))}
        </motion.div>

        {/* Main Content Grid */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          
          {/* Lessons - 2/3 width */}
          <div className="lg:col-span-2">
            <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
              <span>📚</span> Continue Learning
            </h2>
            
            {loading ? (
              <div className="space-y-4">
                {[1,2,3].map(i => (
                  <div key={i} className="h-24 bg-gray-800 rounded-2xl animate-pulse" />
                ))}
              </div>
            ) : (
              <div className="space-y-4">
                {lessons.slice(0, 6).map((lesson, i) => (
                  <motion.div
                    key={lesson.id}
                    variants={itemVariants}
                    initial="hidden"
                    animate="visible"
                    transition={{ delay: i * 0.1 }}
                  >
                    <LessonCard lesson={lesson} />
                  </motion.div>
                ))}
              </div>
            )}
          </div>

          {/* Sidebar - 1/3 width */}
          <div className="space-y-6">
            {/* XP Progress */}
            <XPProgress xp={user?.xp_points || 0} level={user?.level || 1} />
            
            {/* Daily Goal */}
            <DailyGoal />
            
            {/* Streak Calendar */}
            <StreakCalendar streakDays={user?.streak_days || 0} />
            
            {/* Quick Practice Button */}
            <Link to="/practice">
              <motion.button
                whileHover={{ scale: 1.02 }}
                whileTap={{ scale: 0.98 }}
                className="w-full py-4 bg-gradient-to-r from-purple-600 to-indigo-600 rounded-2xl font-bold text-lg flex items-center justify-center gap-3 hover:from-purple-700 hover:to-indigo-700 transition-all"
              >
                <span>📷</span>
                Practice with Webcam
              </motion.button>
            </Link>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
